const Context = React.createContext({
    bookmarksRef: null,
    setBookmarksRef: () => {},
    recommendedMovie: [],
    updateRecommended: () => {},
    searchResult: {},
    updateSearchResult: () => {},
    bookmarkedMovies: [],
    movieInfo: {},
});

