export const Provider = (props) => {
    const [movies, updateRecommendedMovies] = useState([]);
    const [searchResult, updateSearch] = useState({});
    const [bookmarksRef, updateBookmarksRef] = useState(null);
    const [movieInfo, updateCurrentMovie] = useState({});
